class Solution {
public:
    int triangleNumber(vector<int>& nums) {
        sort(nums.begin(),nums.end()); int n=nums.size(), ans=0;
        for(int k=n-1;k>=2;k--){
            int l=0,r=k-1;
            while(l<r){
                if(nums[l]+nums[r]>nums[k]){ ans+=r-l; r--; }
                else l++;
            }
        }
        return ans;
    }
};

